// Determine the conversation state and route accordingly
const data = $input.first().json;
const state = data.conversation_state || {};
const currentStep = state.step || 'greeting';
const messageText = (data.text || data.interactive_title || '').toLowerCase().trim();
const interactiveId = data.interactive_id || '';

// Keywords that trigger specific flows
const bookingKeywords = ['book', 'appointment', 'schedule', 'doctor', 'consult', 'visit'];
const cancelKeywords = ['cancel', 'delete', 'remove'];
const rescheduleKeywords = ['reschedule', 'change', 'move', 'postpone'];
const statusKeywords = ['status', 'check', 'my appointment', 'upcoming'];
const helpKeywords = ['help', 'menu', 'hi', 'hello', 'hey', 'start'];

let route = currentStep;

// If no active flow, detect intent from message
if (currentStep === 'greeting' || currentStep === 'idle') {
  if (bookingKeywords.some(k => messageText.includes(k)) || interactiveId === 'btn_book') {
    route = 'start_booking';
  } else if (cancelKeywords.some(k => messageText.includes(k)) || interactiveId === 'btn_cancel') {
    route = 'cancel_appointment';
  } else if (rescheduleKeywords.some(k => messageText.includes(k)) || interactiveId === 'btn_reschedule') {
    route = 'reschedule_appointment';
  } else if (statusKeywords.some(k => messageText.includes(k)) || interactiveId === 'btn_status') {
    route = 'check_status';
  } else if (helpKeywords.some(k => messageText.includes(k))) {
    route = 'greeting';
  } else {
    route = 'ai_understand';  // Use AI to understand intent
  }
}

return [{ ...data, route, currentStep }];

