// User confirmed — create the appointment
const data = $input.first().json;
const interactiveId = data.interactive_id || '';

if (interactiveId.startsWith('confirm_yes_')) {
  const parts = interactiveId.replace('confirm_yes_', '').split('_');
  const time = parts[0];
  const date = parts[1];
  const doctorId = parts.slice(2).join('_');
  return [{ ...data, booking_time: time, booking_date: date, booking_doctor_id: doctorId, confirmed: true }];
} else {
  return [{ ...data, confirmed: false }];
}

