// Parse AI response and route accordingly
const aiResponse = $input.first().json;
let parsed;
try {
  const content = aiResponse.message?.content || aiResponse.choices?.[0]?.message?.content || '{}';
  parsed = JSON.parse(content);
} catch(e) {
  parsed = { intent: 'GREETING', reply: 'I\'m not sure I understood that. Let me show you the menu!', confidence: 0.5 };
}

const intentMap = {
  'BOOK': 'start_booking',
  'CANCEL': 'cancel_appointment',
  'RESCHEDULE': 'reschedule_appointment',
  'STATUS': 'check_status',
  'GREETING': 'greeting',
  'FAQ': 'greeting'
};

const phone = $('Intent Router').first().json.phone;

return [{
  route: intentMap[parsed.intent] || 'greeting',
  ai_reply: parsed.reply,
  confidence: parsed.confidence,
  phone
}];
